import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import MedicalDisclaimer from "@/components/MedicalDisclaimer";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is body surface area?", a: "Body surface area, or BSA, estimates the total external surface area of the body in square meters." },
  { q: "How do you calculate BSA?", a: "BSA is usually calculated from height and weight using formulas such as Mosteller, DuBois, Haycock, Gehan and George, or Boyd." },
  { q: "Why is BSA used in medicine?", a: "BSA is used in some medical settings because it can scale certain measurements and doses better than weight alone." },
  { q: "What is the Mosteller formula?", a: "The Mosteller formula is BSA = square root of height in centimeters times weight in kilograms divided by 3600." },
  { q: "How is BSA used for drug dosing?", a: "Some medications, especially certain chemotherapy drugs, may be dosed by BSA under professional medical supervision." },
];

const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
const lbToKg = (lb: number) => lb * 0.45359237;
const inToCm = (inch: number) => inch * 2.54;
const fmt = (n: number) => `${n.toFixed(2)} m2`;
function bsa(heightIn: number, weightLb: number) {
  const h = inToCm(heightIn);
  const w = lbToKg(weightLb);
  const mosteller = Math.sqrt((h * w) / 3600);
  const dubois = 0.007184 * Math.pow(h, 0.725) * Math.pow(w, 0.425);
  const haycock = 0.024265 * Math.pow(h, 0.3964) * Math.pow(w, 0.5378);
  const gehan = 0.0235 * Math.pow(h, 0.42246) * Math.pow(w, 0.51456);
  const boyd = 0.0003207 * Math.pow(h, 0.3) * Math.pow(w, 0.7285 - 0.0188 * Math.log10(w));
  const average = (mosteller + dubois + haycock + gehan + boyd) / 5;
  return { mosteller, dubois, haycock, gehan, boyd, average };
}
function heightLabel(inches: number) {
  return `${Math.floor(inches / 12)}ft ${inches % 12}in`;
}

export default function BodySurfaceAreaCalculator() {
  const [height, setHeight] = useState(70);
  const [weight, setWeight] = useState(176);
  const result = useMemo(() => bsa(height, weight), [height, weight]);
  const heights = [60, 64, 68, 72, 76];
  const weights = [130, 154, 176, 198, 220];
  return (
    <>
      <SEOHead title="Free Body Surface Area Calculator Online - Calculate BSA Instantly | CalcHive" description="Free online body surface area calculator. Calculate BSA using Mosteller, DuBois, Haycock and other formulas for any height and weight instantly. 100% free, no signup required." canonical="/body-surface-area-calculator" keywords="free body surface area calculator, BSA calculator free online, Mosteller formula calculator free, calculate body surface area free, medical BSA calculator free online" category="Health Calculators" breadcrumbName="Free Body Surface Area Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10"><div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-teal-600 dark:text-teal-400 bg-teal-50 dark:bg-teal-950/50 px-3 py-1 rounded-full mb-4 inline-block">Health</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Body Surface Area Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate body surface area with five common clinical formulas and compare the average result.</p></div><AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8"><div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold block mb-2">Height (in)</label><input type="number" value={height} onChange={(e) => setHeight(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold block mb-2">Weight (lb)</label><input type="number" value={weight} onChange={(e) => setWeight(Number(e.target.value))} className={inputClass} /></div></div><div className="bg-gradient-to-br from-teal-500 to-teal-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Average BSA</p><p className="text-5xl sm:text-6xl font-black text-white">{fmt(result.average)}</p></div><div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mt-4">{[["Mosteller", result.mosteller], ["DuBois", result.dubois], ["Haycock", result.haycock], ["Gehan and George", result.gehan], ["Boyd", result.boyd]].map(([label, value]) => <div key={label as string} className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">{label as string}</p><p className="text-lg font-extrabold">{fmt(value as number)}</p></div>)}</div></section><MedicalDisclaimer /><ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold">How to Calculate Body Surface Area for Free</h2><p className="text-muted-foreground leading-relaxed">Enter height and weight to calculate BSA with Mosteller, DuBois, Haycock, Gehan and George, and Boyd formulas.</p><h2 className="text-2xl font-bold">Which BSA Formula Is Most Accurate</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold mb-3">Body Surface Area by Height and Weight</caption><thead className="bg-muted/60"><tr>{["Height", "130 lbs BSA", "154 lbs BSA", "176 lbs BSA", "198 lbs BSA", "220 lbs BSA"].map((h) => <th key={h} className="text-left py-3 px-3">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{heights.map((h) => <tr key={h}><td className="py-2.5 px-3 font-semibold">{heightLabel(h)}</td>{weights.map((w) => <td key={w} className="py-2.5 px-3">{fmt(bsa(h, w).mosteller)}</td>)}</tr>)}</tbody></table></div><h2 className="text-2xl font-bold">Free BSA Calculator for Medical Students and Everyone</h2><p className="text-muted-foreground leading-relaxed">BSA is useful for learning and rough clinical context, but medical dosing decisions should always be made by qualified professionals.</p></section>
        <section className="mb-8"><h3 className="text-xl font-bold mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section><AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/body-surface-area-calculator" headingLevel="h3" /></main>
    </>
  );
}


